import Marquee from "react-fast-marquee";
import { motion } from "framer-motion";

const MovingGallery = () => {
  const videos = [
    "/assets/videos/cooking.mp4",
    "/assets/videos/vid2.mp4",
    "/assets/videos/vid3.mp4",
    "/assets/videos/vid5.mp4",
    "/assets/videos/vid6.mp4"
  ];

  const images = [
    "/assets/amb.jpg",
    "/assets/apr.jpg",
    "/assets/ballent.jpg",
    "/assets/bl.jpg",
    "/assets/bn.jpg",
    "/assets/dj.jpg",
    "/assets/dri.jpg",
    "/assets/f1.jpg",
    "/assets/grp.jpg",
    "/assets/nod.jpg"
  ];

  return (
    <div className="w-full py-24 bg-black">
      {/* Title */}
      <motion.div 
        className="text-center mb-24 px-8"
        initial={{ opacity: 0 }}
        whileInView={{ opacity: 1 }}
      >
        <span className="block text-gold text-2xl font-bold tracking-wider uppercase mb-8 px-12 py-6 bg-black rounded-full border-2 border-gold">
          The Vibe
        </span>
        <h2 className="text-6xl font-black text-white drop-shadow-2xl">
          CORRIDOR
        </h2>
        <h3 className="text-3xl font-light text-zinc-400 tracking-wide">
          in motion
        </h3>
      </motion.div>

      {/* Video Marquee */}
      <div className="w-screen">
        <Marquee speed={35} gradient={false} pauseOnHover>
          {videos.map((src, index) => (
            <div key={index} className="inline-block w-[240px] h-[420px] mx-[2px]">
              <video 
                src={src}
                className="w-full h-full object-cover rounded-3xl shadow-[0_25px_50px_rgba(0,0,0,1)] border-8 border-black"
                muted 
                autoPlay 
                loop 
                playsInline
                preload="metadata"
              />
            </div>
          ))}
        </Marquee>
      </div>

      {/* Image Marquees */}
      <div className="mt-32">
        {/* LTR */}
        <Marquee speed={80} gradient={false} pauseOnHover className="mb-12">
          {images.map((src, index) => (
            <motion.div 
              key={index}
              className="inline-block w-[340px] h-[240px] mx-[1px]"
              whileHover={{ scale: 1.05 }}
            >
              <img 
                src={src}
                className="w-full h-full object-cover rounded-2xl shadow-2xl border-4 border-transparent hover:border-gold grayscale hover:grayscale-0 transition-all duration-500"
                loading="eager"
              />
            </motion.div>
          ))}
        </Marquee>

        {/* RTL */}
        <Marquee speed={80} direction="right" gradient={false} pauseOnHover>
          {images.slice(0, 7).map((src, index) => (
            <motion.div 
              key={"r" + index}
              className="inline-block w-[340px] h-[240px] mx-[1px]"
              whileHover={{ scale: 1.05 }}
            >
              <img 
                src={src}
                className="w-full h-full object-cover rounded-2xl shadow-2xl border-4 border-transparent hover:border-gold grayscale hover:grayscale-0 transition-all duration-500"
                loading="eager"
              />
            </motion.div>
          ))}
        </Marquee>
      </div>
    </div>
  );
};

export default MovingGallery;
